changeSet.rollback:
DROP POLICY IF EXISTS tenant_isolation ON nexus.memory;
ALTER TABLE nexus.memory NO FORCE ROW LEVEL SECURITY;
ALTER TABLE nexus.memory DISABLE ROW LEVEL SECURITY;

changeSet.sql:
DO $$
BEGIN
    IF EXISTS (SELECT 1 FROM pg_roles WHERE rolname = 'nexus_svc') THEN
        EXECUTE 'GRANT USAGE ON SCHEMA nexus TO nexus_svc';
        EXECUTE 'GRANT SELECT, INSERT, UPDATE, DELETE ON nexus.memory TO nexus_svc';
        EXECUTE 'GRANT USAGE ON SEQUENCE nexus.memory_id_seq TO nexus_svc';
        EXECUTE 'ALTER ROLE nexus_svc SET search_path TO nexus, public';
        RAISE NOTICE 'Granted nexus.memory privileges to nexus_svc';
    ELSE
        RAISE NOTICE 'nexus_svc role not found; skipping grants (create role before first run)';
    END IF;
END
$$;
